// Gather all diagnostic results and build report
const webhookData = $('Webhook').first().json.body;
const responseUrl = webhookData.response_url || '';
const userId = webhookData.user_id || 'unknown';
const channelId = webhookData.channel_id || '';

// Ollama models
let modelsStatus = '❌ Unreachable';
let modelsList = [];
try {
  const modelsData = $('Ollama Models').first().json;
  modelsList = (modelsData.models || []).map(m => m.name);
  modelsStatus = `✅ ${modelsList.length} models available`;
} catch(e) { modelsStatus = `❌ Error: ${e.message}`; }

// Ollama running
let runningStatus = '❌ No models loaded';
try {
  const psData = $('Ollama Running').first().json;
  const running = psData.models || [];
  runningStatus = running.length > 0
    ? `✅ ${running.map(m => m.name).join(', ')}`
    : '⚠️ No models currently loaded in VRAM';
} catch(e) { runningStatus = `❌ Error: ${e.message}`; }

// Kevin ping
let kevinStatus = '❌ No response';
try {
  const kevinData = $('Kevin Ping').first().json;
  const reply = kevinData.message?.content || '';
  kevinStatus = reply.trim() ? `✅ Responded: "${reply.trim().slice(0, 50)}"` : '⚠️ Empty response';
} catch(e) { kevinStatus = `❌ Error: ${e.message}`; }

// n8n health
let n8nStatus = '❌ Unreachable';
try {
  const n8nData = $('n8n Health').first().json;
  n8nStatus = n8nData.status === 'ok' ? '✅ Healthy' : `⚠️ Status: ${n8nData.status}`;
} catch(e) { n8nStatus = `❌ Error: ${e.message}`; }

// Slack auth
let slackStatus = '❌ Auth failed';
try {
  const slackData = $('Slack Auth Test').first().json;
  if (slackData.ok) {
    slackStatus = `✅ Connected as @${slackData.bot_id || slackData.user_id}`;
  } else {
    slackStatus = `❌ Error: ${slackData.error}`;
  }
} catch(e) { slackStatus = `❌ Error: ${e.message}`; }

// Personality models check
const personalities = ['kevin:latest', 'jason:latest', 'scaachi:latest', 'christian:latest', 'chidi:latest'];
const missingPersonalities = personalities.filter(p => !modelsList.includes(p));
const personalitiesStatus = missingPersonalities.length === 0
  ? `✅ All 5 personalities loaded`
  : `⚠️ Missing: ${missingPersonalities.join(', ')}`;

// Build the report
const now = new Date().toISOString().slice(0, 19).replace('T', ' ') + ' UTC';

const reportText = [
  `*🔬 AI Workers Diagnostic Report*`,
  `_Run by <@${userId}> at ${now}_`,
  ``,
  `*Infrastructure*`,
  `• n8n Automation: ${n8nStatus}`,
  `• Slack API: ${slackStatus}`,
  ``,
  `*Ollama / Models*`,
  `• Ollama Service: ${modelsStatus}`,
  `• Personalities: ${personalitiesStatus}`,
  `• VRAM Loaded: ${runningStatus}`,
  ``,
  `*Live Test*`,
  `• Kevin Response: ${kevinStatus}`,
  ``,
  `*Available Models (${modelsList.length})*`,
  modelsList.length > 0 ? modelsList.map(m => `  · ${m}`).join('\n') : '  _none_'
].join('\n');

return [{ json: { responseUrl, channelId, reportText } }];
